parameters.jsCode:
// L'agent peut retourner plusieurs items (un par input du Merge)
// On prend le premier qui a un output valide
const allItems = $input.all();
let input = null;

for (const item of allItems) {
  const candidate = item.json.output || item.json;
  if (candidate && (candidate.report_period || candidate.headline)) {
    input = candidate;
    break;
  }
}

if (!input) {
  input = allItems[0].json.output || allItems[0].json;
}

// Helper : nettoyer les caractères interdits dans les champs structurels
function sanitize(str) {
  if (!str) return str;
  return str
    .replace(/['']/g, ' ')
    .replace(/[""]/g, "'")
    .replace(/[/\\]/g, '-')
    .replace(/[—–]/g, '-')
    .replace(/[&]/g, 'and')
    .replace(/[éèêë]/g, 'e')
    .replace(/[àâä]/g, 'a')
    .replace(/[ùûü]/g, 'u')
    .replace(/[ôö]/g, 'o')
    .replace(/[îï]/g, 'i')
    .replace(/[ç]/g, 'c')
    .replace(/[ÉÈÊË]/g, 'E')
    .replace(/[ÀÂÄ]/g, 'A')
    .replace(/[ÙÛÜ]/g, 'U')
    .replace(/[ÔÖ]/g, 'O')
    .replace(/[ÎÏ]/g, 'I')
    .replace(/[Ç]/g, 'C')
    .replace(/[()[\]@%$!?*+={}|<>~`^#]/g, '')
    .trim();
}

// Mois FR → EN
const monthMap = {
  'janvier': 'January', 'février': 'February', 'mars': 'March',
  'avril': 'April', 'mai': 'May', 'juin': 'June',
  'juillet': 'July', 'août': 'August', 'septembre': 'September',
  'octobre': 'October', 'novembre': 'November', 'décembre': 'December'
};

function translatePeriod(str) {
  if (!str) return str;
  let result = str;
  for (const [fr, en] of Object.entries(monthMap)) {
    result = result.replace(new RegExp(fr, 'gi'), en);
  }
  return result;
}

const errors = [];

// 1. company_id : UUID valide ou null
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (input.company_id && !uuidRegex.test(input.company_id)) {
  errors.push(`company_id invalid: ${input.company_id}`);
  input.company_id = null;
  input.company_not_found = true;
}

// 2. company_name : sanitize
if (input.company_name) {
  input.company_name = sanitize(input.company_name);
}

// 3. report_date : format YYYY-MM-DD
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!dateRegex.test(input.report_date)) {
  errors.push(`report_date invalid: ${input.report_date}`);
  const d = new Date(input.report_date);
  if (!isNaN(d.getTime())) {
    input.report_date = d.toISOString().split('T')[0];
  }
}

// 4. report_period : traduire FR→EN, sanitize
if (input.report_period) {
  input.report_period = translatePeriod(input.report_period);
  input.report_period = sanitize(input.report_period);
}

// 5. storage_period : recalculer depuis report_period
if (input.report_period) {
  input.storage_period = input.report_period.replace(/\s/g, '_');
}

// 6. report_type : enum strict
const validTypes = ['monthly', 'bimonthly', 'quarterly', 'semi-annual', 'annual'];
if (input.report_type) {
  input.report_type = input.report_type.toLowerCase().trim();
  if (!validTypes.includes(input.report_type)) {
    errors.push(`report_type invalid: ${input.report_type}`);
    const typeMap = {
      'mensuel': 'monthly', 'bimensuel': 'bimonthly', 'trimestriel': 'quarterly',
      'semestriel': 'semi-annual', 'annuel': 'annual'
    };
    input.report_type = typeMap[input.report_type] || 'monthly';
  }
}

// 7. report_title : sanitize léger (garder accents FR)
if (input.report_title) {
  input.report_title = input.report_title
    .replace(/[/\\]/g, '-')
    .replace(/[[\]"&]/g, '')
    .trim();
}

// 8. metrics : forcer toutes les valeurs en nombre, supprimer les nulls
if (input.metrics && typeof input.metrics === 'object') {
  const cleanMetrics = {};
  for (const [key, value] of Object.entries(input.metrics)) {
    const cleanKey = key.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
    const numVal = Number(value);
    if (value !== null && value !== undefined && !isNaN(numVal)) {
      cleanMetrics[cleanKey] = numVal;
    }
  }
  input.metrics = cleanMetrics;

  if (input.metrics.runway_months && input.metrics.runway_days) {
    delete input.metrics.runway_days;
  }
  if (input.metrics.runway_years) {
    input.metrics.runway_months = input.metrics.runway_years * 12;
    delete input.metrics.runway_years;
  }
}

// 9. key_highlights : forcer array de strings
if (!Array.isArray(input.key_highlights)) {
  input.key_highlights = input.key_highlights ? [String(input.key_highlights)] : [];
}
input.key_highlights = input.key_highlights.map(h => String(h).replace(/"/g, "'"));

// 10. Nettoyage des champs company_not_found
if (input.company_id) {
  delete input.company_not_found;
  delete input.company_name_from_report;
}

// 11. workspace_id : valider UUID si présent
if (input.workspace_id && !uuidRegex.test(input.workspace_id)) {
  errors.push(`workspace_id invalid: ${input.workspace_id}`);
  input.workspace_id = null;
}

return {
  json: {
    ...input,
    _validation_errors: errors.length > 0 ? errors : undefined,
    _validated: true,
    has_attachments: $('Premier filtre').first().json.has_analyzable_attachments || false,
    cleaned_content: $('Clean original text report').first().json.html_content || '',
    email_from: $('Start + Download').first().json.from.value[0].address,
    email_subject: $('Clean original text report').first().json.email_subject || $('Start + Download').first().json.subject,
    email_cc_0: $('Start + Download').first().json.cc?.value?.[0]?.address || '',
    email_cc_1: $('Start + Download').first().json.cc?.value?.[1]?.address || ''
  }
};

