// ============================================
// START + DOWNLOAD ALL ATTACHMENTS
// 1. Reformate le payload webhook Unipile
// 2. Télécharge TOUS les fichiers attachés (PDF, Excel, etc.)
// ============================================
const body = $input.first().json.body;

// --- Reformater from/to/cc au format Gmail Trigger ---
const from = {
  value: [{
    address: body.from_attendee?.identifier || '',
    name: body.from_attendee?.display_name || ''
  }]
};
const to = {
  value: (body.to_attendees || []).map(a => ({
    address: a.identifier || '',
    name: a.display_name || ''
  }))
};
const cc = {
  value: (body.cc_attendees || []).map(a => ({
    address: a.identifier || '',
    name: a.display_name || ''
  }))
};

// --- Filtrer les attachments valides (exclure les images inline) ---
const validAttachments = (body.attachments || []).filter(att => {
  // Exclure les images inline (avec cid et mime image/*)
  if (att.cid && (att.mime || '').startsWith('image/')) return false;
  return true;
});

// --- Base JSON compatible Gmail Trigger ---
const baseJson = {
  // Compat Gmail Trigger
  id: body.email_id,
  threadId: body.thread_id,
  subject: body.subject || '(Sans objet)',
  from: from,
  from_value: from.value,
  to: to,
  cc: cc,
  date: body.date,
  text: body.body_plain || '',
  html: body.body || '',
  snippet: (body.body_plain || '').substring(0, 200),
  // Unipile
  unipile_email_id: body.email_id,
  unipile_account_id: body.account_id,
  message_id: body.message_id,
  provider_id: body.provider_id,
  folders: body.folders || [],
  route: body._route || 'report',
  // Attachments
  hasAttachments: body.has_attachments || false,
  attachmentCount: validAttachments.length,
  email: body.from_attendee?.identifier || ''
};

// --- Si pas d'attachments, retourner sans binary ---
if (validAttachments.length === 0) {
  return [{
    json: {
      ...baseJson,
      hasAttachments: false,
      files: []
    }
  }];
}

// --- Télécharger TOUS les fichiers via Unipile API ---
const UNIPILE_BASE = 'https://api27.unipile.com:15779';
const UNIPILE_KEY = '5vOB1abl.vo5PqByMrhrCdlw+XpyV0gio8d/kKM4xxxmaNQgqxZA=';

const downloadedFiles = [];
const failedFiles = [];
const binaryData = {};

for (const attachment of validAttachments) {
  const urls = [
    `${UNIPILE_BASE}/api/v1/emails/${body.email_id}/attachments/${attachment.id}`,
    `${UNIPILE_BASE}/api/v1/emails/${body.provider_id}/attachments/${attachment.id}?account_id=${body.account_id}`,
  ];

  let downloaded = false;
  const errors = [];

  for (const url of urls) {
    try {
      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: url,
        headers: { 'X-API-KEY': UNIPILE_KEY },
        encoding: 'arraybuffer',
        returnFullResponse: false,
      });

      // Générer un nom de clé unique pour le binary (sans caractères spéciaux)
      const safeKey = `file_${downloadedFiles.length}`;

      binaryData[safeKey] = await this.helpers.prepareBinaryData(
        Buffer.from(response),
        attachment.name || `attachment_${downloadedFiles.length}`,
        attachment.mime || 'application/octet-stream'
      );

      downloadedFiles.push({
        key: safeKey,
        name: attachment.name,
        extension: attachment.extension,
        size: attachment.size,
        sizeMB: ((attachment.size || 0) / (1024 * 1024)).toFixed(2),
        mime: attachment.mime,
        id: attachment.id
      });

      downloaded = true;
      break; // Sortir de la boucle des URLs si succès

    } catch (err) {
      errors.push(err.message);
      continue;
    }
  }

  if (!downloaded) {
    failedFiles.push({
      name: attachment.name,
      extension: attachment.extension,
      size: attachment.size,
      error: errors.join(' | ')
    });
  }
}

// --- Retourner le résultat avec tous les binaries ---
return [{
  json: {
    ...baseJson,
    hasAttachments: downloadedFiles.length > 0,
    downloadedCount: downloadedFiles.length,
    failedCount: failedFiles.length,
    files: downloadedFiles,
    failedFiles: failedFiles,
    // Pour compatibilité avec le reste du workflow
    hasPdf: downloadedFiles.some(f => f.extension === 'pdf'),
    hasExcel: downloadedFiles.some(f => ['xlsx', 'xls'].includes(f.extension)),
    // Liste des fichiers par type
    pdfFiles: downloadedFiles.filter(f => f.extension === 'pdf'),
    excelFiles: downloadedFiles.filter(f => ['xlsx', 'xls'].includes(f.extension)),
  },
  binary: binaryData
}];

// ============================================
// PREMIER FILTRE — Multi-route splitter
// Émet UN ITEM PAR TYPE DÉTECTÉ
// routeType numérique pour le Switch
// 0 = text_only (toujours émis)
// 1 = pdf
// 2 = excel  
// 3 = image inline
// 4 = notion
// 5 = google_drive
// 6 = docsend
// 7 = sendbim
// ============================================

const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json || item;

  const textContent = email.text || email.snippet || '';
  const htmlContent = email.html || '';
  const fullContent = textContent + ' ' + htmlContent;
  const subject = email.subject || '';

  // === BASE COMMUNE ===
  const base = {
    emailId: email.id || email.unipile_email_id || '',
    threadId: email.threadId || '',
    messageId: email.message_id || '',
    providerId: email.provider_id || '',
    accountId: email.unipile_account_id || '',
    subject: subject,
    from: email.from || '',
    fromEmail: email.email || '',
    to: email.to || '',
    cc: email.cc || '',
    date: email.date || '',
    bodyText: textContent,
    bodyHtml: htmlContent,
  };

  // === FICHIERS TÉLÉCHARGÉS ===
  const files = email.files || [];
  const pdfFiles = files.filter(f => (f.extension || '').toLowerCase() === 'pdf');
  const excelFiles = files.filter(f => ['xlsx', 'xls', 'xlsm', 'csv'].includes((f.extension || '').toLowerCase()));

  // === IMAGES INLINE (> 20KB) ===
  const imageFiles = files.filter(f => {
    const ext = (f.extension || '').toLowerCase();
    return ['png', 'jpg', 'jpeg'].includes(ext) && (f.size || 0) > 20000;
  });
  let rawAttachments = [];
  try { rawAttachments = $('Webhook').first().json.body?.attachments || []; } catch(e) {}
  const inlineImageAttachments = rawAttachments.filter(att => {
    const mime = (att.mime || '').toLowerCase();
    return att.cid 
      && (mime === 'image/png' || mime === 'image/jpeg' || mime === 'image/jpg')
      && (att.size || 0) > 20000;
  });

  // === DÉTECTION LIENS ===
  function extractNotionLinks(content) {
    const links = []; const seen = new Set();
    [/https?:\/\/(www\.)?notion\.so\/[^\s<")']+/gi, /https?:\/\/[a-zA-Z0-9-]+\.notion\.site\/[^\s<")']+/gi].forEach(rx => {
      let m; while ((m = rx.exec(content)) !== null) {
        const url = m[0].replace(/[<>"')]+$/, '');
        if (!seen.has(url)) { seen.add(url); links.push({ url }); }
      }
    });
    let hm; const hrefRx = /href=["']([^"']*notion\.(so|site)[^"']*)["']/gi;
    while ((hm = hrefRx.exec(content)) !== null) {
      if (!seen.has(hm[1])) { seen.add(hm[1]); links.push({ url: hm[1] }); }
    }
    return links;
  }

  function extractGoogleDriveLinks(content) {
    const links = []; const seenIds = new Set();
    const patterns = [
      { rx: /https?:\/\/drive\.google\.com\/file\/d\/([a-zA-Z0-9_-]+)[^\s<")'"]*/gi, grp: 1 },
      { rx: /https?:\/\/drive\.google\.com\/open\?id=([a-zA-Z0-9_-]+)/gi, grp: 1 },
      { rx: /https?:\/\/docs\.google\.com\/(document|presentation|spreadsheets|drawings)\/d\/([a-zA-Z0-9_-]+)[^\s<")'"]*/gi, grp: 2 },
      { rx: /https?:\/\/drive\.google\.com\/drive\/folders\/([a-zA-Z0-9_-]+)[^\s<")'"]*/gi, grp: 1 }
    ];
    for (const p of patterns) {
      let m; while ((m = p.rx.exec(content)) !== null) {
        const url = m[0].replace(/[<>"')]+$/, ''); const fileId = m[p.grp];
        if (!seenIds.has(fileId)) { seenIds.add(fileId); links.push({ url, fileId }); }
      }
    }
    return links;
  }

  function extractDocSendLinks(content) {
    const links = []; const seen = new Set();
    [/https?:\/\/(www\.)?docsend\.com\/(view|v)\/[a-zA-Z0-9_-]+/gi, /https?:\/\/(www\.)?docsend\.com\/d\/[a-zA-Z0-9_-]+/gi, /https?:\/\/[a-zA-Z0-9-]+\.docsend\.com\/view\/[a-zA-Z0-9_-]+/gi].forEach(rx => {
      let m; while ((m = rx.exec(content)) !== null) { if (!seen.has(m[0])) { seen.add(m[0]); links.push({ url: m[0] }); } }
    });
    let hm; const hrefRx = /href=["']([^"']*docsend\.com[^"']*)["']/gi;
    while ((hm = hrefRx.exec(content)) !== null) { if (!seen.has(hm[1])) { seen.add(hm[1]); links.push({ url: hm[1] }); } }
    return links;
  }

