function excelDateToLabel(serial) {
  if (typeof serial !== 'number' || serial < 40000) return String(serial);
  const date = new Date((serial - 25569) * 86400000);
  const months = ['Jan','Fév','Mar','Avr','Mai','Jun','Jul','Aoû','Sep','Oct','Nov','Déc'];
