  if (key === '__EMPTY') {
    columnHeaders[key] = 'Poste';
    continue;
  }

  const headerVal = headerRow[key] || '';
  const dateVal = dateRow[key];

  let dateLabel = '';
  if (typeof dateVal === 'number' && dateVal > 40000) {
    dateLabel = excelDateToLabel(dateVal);
  } else if (typeof dateVal === 'string') {
    dateLabel = dateVal; // "YTD"
  }

  if (dateLabel && headerVal) {
