                    label.includes('Gross Margin') || label.includes('CASH FLOW') ||
                    label.includes('FREE CASH FLOW');
    const prefix = isTotal ? '▶ ' : '  ';

    sections.push(`${prefix}${label}\n    ${values.join(' | ')}`);
  }
}

