  'Consulting', 'HR', 'entertainment', 'IT Expenses', 'Operational Tools',
  'Labour', 'BRANDED PARTNERSHIP'
];

// --- HELPERS ---
function parseValue(raw) {
  if (!raw) return null;
  raw = raw.trim();
  if (raw.endsWith('%')) return raw;
  const cleaned = raw.replace('€', '').replace(/\s/g, '').trim();
  const num = parseInt(cleaned, 10);
  return isNaN(num) ? raw : num;
}

function parseDataLine(line) {
  const result = { monthly: {}, ytd: {} };
  const segments = line.split(' | ');
  for (const seg of segments) {
    const trimmed = seg.trim();
    const ytdMatch = trimmed.match(/^YTD\s+(ACTUAL|BUDGET|DELTA):\s*(.+)$/);
    if (ytdMatch) {
      result.ytd[ytdMatch[1].toLowerCase()] = parseValue(ytdMatch[2]);
      continue;
    }
    const monthMatch = trimmed.match(/^(\w+)\s+(\d{4})\s+(ACTUAL|BUDGET|DELTA):\s*(.+)$/);
    if (monthMatch) {
      const monthNum = MONTHS_MAP[monthMatch[1]];
      if (!monthNum) continue;
      const key = `${monthMatch[2]}-${monthNum}`;
      if (!result.monthly[key]) result.monthly[key] = {};
      result.monthly[key][monthMatch[3].toLowerCase()] = parseValue(monthMatch[4]);
    }
  }
  return result;
}

function toSnakeCase(label) {
  return label
    .toLowerCase()
    .replace(/[()]/g, '')
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_|_$/g, '');
}

function categorizeLabel(label) {
  if (REVENUE_LABELS.some(r => label.includes(r))) return 'revenue';
  if (COST_LABELS.some(c => label.includes(c))) return 'cost';
  return 'other';
}

