let currentLabel = null;
let isMainKPI = false;

for (const line of lines) {
  if (!line.trim() || line.startsWith('📊') || line.startsWith('===') || 
      line.startsWith('Fichier') || line.startsWith('Lignes')) continue;

  if (line.match(/^\s{2}2WATCH GROUP/) || line.match(/^\s{2}[A-Z].+GROUP/)) {
    currentEntity = line.trim().toLowerCase().replace(/\s+/g, '_');
    continue;
  }

  if (line.startsWith('▶')) {
    currentLabel = line.replace('▶', '').trim();
    isMainKPI = true;
    continue;
  }

  if (line.match(/^\s{2}\S/) && !line.match(/^\s{4}/)) {
    currentLabel = line.trim();
    isMainKPI = false;
    continue;
  }

  if (line.match(/^\s{4}/) && currentLabel) {
    const data = parseDataLine(line.trim());
    if (!financialData.entities[currentEntity]) {
      financialData.entities[currentEntity] = { kpis: {}, details: {}, percentages: {} };
    }
    const entity = financialData.entities[currentEntity];
    if (currentLabel.startsWith('%')) entity.percentages[currentLabel] = data;
    else if (isMainKPI) entity.kpis[currentLabel] = data;
    else entity.details[currentLabel] = data;
  }
}

