  const lastYear = lastMonth ? lastMonth.split('-')[0] : '2025';

  // Période pour le report_period (format existant : "December 2025")
  const reportPeriodYTD = `${lastYear} YTD`;

  function addMetric(key, value, type, period) {
    if (value === null || value === undefined) return;
    metricsForDb.push({
      metric_key: key,
      metric_value: String(value),
      metric_type: type,
      report_period: period
    });
  }

  // --- KPIs principaux : YTD ---
  for (const [label, data] of Object.entries(mainEntity.kpis)) {
