      addMetric(`${baseKey}_budget`, data.ytd.budget, 'currency', reportPeriodYTD);
    }
    if (data.ytd.delta !== undefined) {
      addMetric(`${baseKey}_delta`, data.ytd.delta, 'currency', reportPeriodYTD);
    }
  }

  // --- KPIs principaux : mensuel (chaque mois = une métrique avec son report_period) ---
