      const [year, monthNum] = month.split('-');
      const monthDisplay = `${MONTHS_DISPLAY[monthNum]} ${year}`;

      if (values.actual !== undefined) {
        addMetric(`${baseKey}_monthly`, values.actual, 'currency', monthDisplay);
      }
      if (values.budget !== undefined) {
        addMetric(`${baseKey}_monthly_budget`, values.budget, 'currency', monthDisplay);
      }
    }
  }

  // --- Détails revenus/coûts : YTD ---
  for (const [label, data] of Object.entries(mainEntity.details)) {
    const baseKey = toSnakeCase(label);
    if (data.ytd && data.ytd.actual !== undefined) {
      const type = typeof data.ytd.actual === 'string' && data.ytd.actual.includes('%') 
        ? 'percentage' : 'currency';
      addMetric(baseKey, data.ytd.actual, type, reportPeriodYTD);
      if (data.ytd.budget !== undefined) {
        addMetric(`${baseKey}_budget`, data.ytd.budget, type, reportPeriodYTD);
      }
    }
  }

  // --- Détails revenus/coûts : mensuel ---
  for (const [label, data] of Object.entries(mainEntity.details)) {
    const baseKey = toSnakeCase(label);
    for (const [month, values] of Object.entries(data.monthly)) {
      const [year, monthNum] = month.split('-');
      const monthDisplay = `${MONTHS_DISPLAY[monthNum]} ${year}`;

      if (values.actual !== undefined) {
        addMetric(`${baseKey}_monthly`, values.actual, 'currency', monthDisplay);
      }
    }
  }

  // --- Marges (%) ---
  for (const [label, data] of Object.entries(mainEntity.percentages)) {
    const baseKey = toSnakeCase(label);
    if (data.ytd) {
      if (data.ytd.actual !== undefined) {
        addMetric(baseKey, data.ytd.actual, 'percentage', reportPeriodYTD);
      }
      if (data.ytd.budget !== undefined) {
        addMetric(`${baseKey}_budget`, data.ytd.budget, 'percentage', reportPeriodYTD);
      }
    }
    // Mensuel %
    for (const [month, values] of Object.entries(data.monthly)) {
      const [year, monthNum] = month.split('-');
      const monthDisplay = `${MONTHS_DISPLAY[monthNum]} ${year}`;
      if (values.actual !== undefined) {
        addMetric(`${baseKey}_monthly`, values.actual, 'percentage', monthDisplay);
      }
    }
  }
}

// ============================================================
// SORTIE 2 : LLM PROMPT (allégé — pas de métriques brutes)
// Le LLM n'a PAS besoin des chiffres détaillés puisqu'ils sont en DB.
// On lui donne juste :
//   - Le contexte email (qui envoie, quand, sujet)
//   - Le narratif du CEO (body de l'email)
//   - Un résumé des KPIs clés pour qu'il puisse commenter
// ============================================================

function formatNum(val) {
  if (val === null || val === undefined) return 'N/A';
  if (typeof val === 'string') return val;
  return new Intl.NumberFormat('fr-FR').format(val) + '€';
}

let llmPrompt = `## CONTEXTE
Source: ${emailFrom}
Date: ${emailDate}
Sujet: ${emailSubject}

## RÉSUMÉ FINANCIER (données Excel extraites)
`;

if (mainEntity) {
  // Seulement les 5-6 KPIs clés en YTD
  const keyKPIs = ['TOTAL REVENUES', 'Gross Margin', 'EBITDA', 'FREE CASH FLOW OF THE PERIOD'];

  for (const kpiName of keyKPIs) {
    const kpi = mainEntity.kpis[kpiName];
    if (kpi && kpi.ytd && kpi.ytd.actual !== undefined) {
      const pctDelta = kpi.ytd.budget && kpi.ytd.budget !== 0
        ? ` (${Math.round((kpi.ytd.actual / kpi.ytd.budget - 1) * 100)}% vs budget)`
        : '';
      llmPrompt += `- ${kpiName}: ${formatNum(kpi.ytd.actual)}${pctDelta}\n`;
    }
  }

  // Marges
  for (const [label, data] of Object.entries(mainEntity.percentages)) {
    if (data.ytd && data.ytd.actual) {
      llmPrompt += `- Marge EBITDA: Actual ${data.ytd.actual} vs Budget ${data.ytd.budget || 'N/A'}\n`;
    }
  }

  // Tendance 3 derniers mois EBITDA
  const ebitda = mainEntity.kpis['EBITDA'];
  if (ebitda) {
    const months = Object.keys(ebitda.monthly).sort();
    if (months.length >= 3) {
      const last3 = months.slice(-3);
      const trend = last3.map(m => {
        const [y, mn] = m.split('-');
        return `${MONTHS_DISPLAY[mn]}: ${formatNum(ebitda.monthly[m].actual)}`;
      }).join(' → ');
      llmPrompt += `- Tendance EBITDA (3 derniers mois): ${trend}\n`;
    }
  }
}

// Ajouter le narratif du CEO (tronqué si trop long)
if (emailBody) {
  // Extraire le contenu principal (avant les signatures)
  const bodyClean = emailBody
    .split(/^--\s*$/m)[0] // Couper avant la signature
    .replace(/\[image:.*?\]/g, '') // Retirer les images
    .replace(/<https?:\/\/[^>]+>/g, '') // Retirer les URLs
    .trim();

  if (bodyClean.length > 100) {
    // Limiter à ~2000 chars pour pas surcharger
    const truncated = bodyClean.length > 2000 
      ? bodyClean.substring(0, 2000) + '...' 
      : bodyClean;
    llmPrompt += `\n## MESSAGE DU CEO\n${truncated}\n`;
  }
}

// ============================================================
// SORTIE 3 : STRUCTURED DATA (backup complet, identique à v1)
// ============================================================
const structuredData = {
  report_type: 'financial_pl_cashflow',
  extraction_date: new Date().toISOString(),
  entities: financialData.entities
};

// ============================================================
// RETURN
// ============================================================
return [{
  json: {
    // Pour la branche DB → Supabase batch upsert
    metrics_for_db: metricsForDb,

    // Pour la branche LLM → analyse narrative
    llm_prompt: llmPrompt,

    // Backup complet
    structured_data: structuredData,

    // Stats
    stats: {
      metrics_count: metricsForDb.length,
      entities_count: Object.keys(financialData.entities).length,
      original_size_chars: extractedText.length,
      llm_prompt_chars: llmPrompt.length,
      llm_prompt_reduction_percent: Math.round(
        (1 - llmPrompt.length / extractedText.length) * 100
      )
    }
  }
}];

// Récupérer les infos du report
const reportId = $('Merge').first().json.report_id;
const companyId = $('Merge').first().json.company_id;
const reportPeriod = $('Merge').first().json.cleaned_report_period;

// Récupérer TOUS les items binaires depuis le noeud de download
// Remplace 'Start + Download' par le nom exact du noeud qui télécharge les fichiers
const downloadItems = $('Start + Download').all();
const results = [];

for (let i = 0; i < downloadItems.length; i++) {
  const item = downloadItems[i];
  const binaryKeys = Object.keys(item.binary || {});

  for (const binaryKey of binaryKeys) {
    const binaryData = item.binary[binaryKey];
    const originalName = binaryData.fileName || `file_${i}`;
    const ext = originalName.includes('.')
      ? originalName.split('.').pop().toLowerCase()
      : 'bin';
    const mimeType = binaryData.mimeType || 'application/octet-stream';

    const cleanName = originalName
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-zA-Z0-9._-]/g, '_')
      .replace(/_+/g, '_');

    const suffix = `_${results.length}`;
    const storagePath = `${companyId}/${reportId}/${reportPeriod}${suffix}.${ext}`;

    results.push({
      json: {
        storagePath,
        originalName,
        cleanName,
        mimeType,
        reportId,
        companyId,
        reportPeriod,
        fileIndex: results.length,
        binaryKey
      },
      binary: {
        data: item.binary[binaryKey]
      }
    });
  }
}

return results;
